export const facts = [
  { id: 1, title: "Three Hearts of Love", emoji: "🐙", animal: "Octopus", category: "Ocean", fact: "Octopuses have three hearts. Two pump blood to the gills, and one pumps it to the rest of the body. When they swim, the heart that delivers blood to the body actually stops beating, which is why they prefer crawling!", image: "🐙" },
  { id: 2, title: "Spiny Situation", emoji: "🦔", animal: "Hedgehog", category: "Mammals", fact: "Hedgehogs have between 5,000 and 7,000 spines on their back! Each spine lasts about a year before it falls out and a new one grows in its place. Baby hedgehogs are born with their spines just below the skin.", image: "🦔" },
  { id: 3, title: "Century Talkers", emoji: "🦜", animal: "Parrot", category: "Birds", fact: "Some parrot species can live over 80 years! The oldest known parrot, Cookie the cockatoo, lived to be 83. They can also learn over 100 words and even understand context.", image: "🦜" },
  { id: 4, title: "Not-So-Related Pandas", emoji: "🐼", animal: "Red Panda", category: "Mammals", fact: "Despite their name, red pandas are NOT related to giant pandas. They are actually more closely related to raccoons, skunks, and weasels! They were named 'panda' nearly 50 years before the giant panda.", image: "🐾" },
  { id: 5, title: "Mood Ring Lizards", emoji: "🦎", animal: "Bearded Dragon", category: "Reptiles", fact: "Bearded dragons can change color based on their mood and body temperature! They darken when cold or stressed, and lighten up when warm and happy. Their 'beard' puffs out and turns black when they're showing off.", image: "🦎" },
  { id: 6, title: "Purring Bunnies", emoji: "🐰", animal: "Rabbit", category: "Mammals", fact: "Rabbits purr when they're happy! Unlike cats, they do it by softly grinding their teeth together. They also do 'binkies' (joyful leaps and twists in the air) when they're feeling playful.", image: "🐰" },
  { id: 7, title: "Dolphin Name Tags", emoji: "🐬", animal: "Dolphin", category: "Ocean", fact: "Each dolphin develops its own unique signature whistle, essentially a name! They use these to call out to specific friends. Dolphins can remember these 'names' for over 20 years.", image: "🐬" },
  { id: 8, title: "Tongue Sniffers", emoji: "🐍", animal: "Snake", category: "Reptiles", fact: "Snakes smell with their tongues! They flick their forked tongue to collect chemical particles from the air, then press it into the Jacobson's organ on the roof of their mouth to 'read' the smells.", image: "🐍" },
  { id: 9, title: "Headbutt Means Love", emoji: "🐱", animal: "Cat", category: "Dogs & Cats", fact: "When your cat headbutts you, it's called 'bunting' and it means they love and trust you! They have scent glands on their forehead, and bunting is their way of marking you as 'theirs.'", image: "🐱" },
  { id: 10, title: "Crow Detectives", emoji: "🐦‍⬛", animal: "Crow", category: "Birds", fact: "Crows can recognize individual human faces for years and will teach other crows who is 'friend' or 'foe.' They've been known to bring gifts to people who feed them, from shiny buttons to earrings!", image: "🐦‍⬛" },
  { id: 11, title: "Immortal Jellyfish", emoji: "🪼", animal: "Jellyfish", category: "Ocean", fact: "The Turritopsis dohrnii jellyfish is biologically immortal! When it gets old or stressed, it can revert its cells back to a younger state, essentially hitting the reset button on aging.", image: "🪼" },
  { id: 12, title: "Mantis Shrimp Vision", emoji: "🦐", animal: "Mantis Shrimp", category: "Ocean", fact: "Mantis shrimp have 16 types of color receptors (humans have just 3). They can see ultraviolet, infrared, AND polarized light. They also punch with the force of a bullet!", image: "🦐" },
  { id: 13, title: "Elephants Mourn", emoji: "🐘", animal: "Elephant", category: "Mammals", fact: "Elephants hold funerals for their dead. They'll gently touch the bones of deceased family members with their trunks and stand vigil for hours. They've even been seen crying.", image: "🐘" },
  { id: 14, title: "Axolotl Superpowers", emoji: "🦎", animal: "Axolotl", category: "Weird & Wonderful", fact: "Axolotls can regenerate entire limbs, their heart, spinal cord, and even parts of their brain with zero scarring! Scientists study them hoping to unlock regeneration secrets for humans.", image: "🦎" },
  { id: 15, title: "Wombat Cube Poop", emoji: "🐻", animal: "Wombat", category: "Weird & Wonderful", fact: "Wombats produce cube-shaped poop! Their intestines have varying elasticity that molds their droppings into cubes so they don't roll away, perfect for territorial marking on rocks and logs.", image: "🐻" },
  { id: 16, title: "Honeybee Democracy", emoji: "🐝", animal: "Honeybee", category: "Weird & Wonderful", fact: "When honeybees need a new home, they hold a democratic vote! Scout bees dance to advertise locations, and the swarm 'votes' by joining the dance of their preferred spot until consensus is reached.", image: "🐝" },
  { id: 17, title: "Sea Otter Hand-Holding", emoji: "🦦", animal: "Sea Otter", category: "Ocean", fact: "Sea otters hold hands while sleeping so they don't drift apart! They also wrap themselves in kelp for the same reason. A group of otters floating together is adorably called a 'raft.'", image: "🦦" },
  { id: 18, title: "Gecko Toe Magic", emoji: "🦎", animal: "Gecko", category: "Reptiles", fact: "Geckos can walk on walls and ceilings thanks to millions of tiny hair-like structures on their toes called setae. Each toe has about 500,000 of them, using molecular forces to stick to surfaces!", image: "🦎" },
  { id: 19, title: "Virgin Birth Dragons", emoji: "🦎", animal: "Komodo Dragon", category: "Reptiles", fact: "Female Komodo dragons can reproduce without males through parthenogenesis! Their eggs develop into healthy offspring that are genetic clones of the mother.", image: "🦎" },
  { id: 20, title: "Breath-Holding Sloths", emoji: "🦥", animal: "Sloth", category: "Mammals", fact: "Sloths can hold their breath underwater for up to 40 minutes, longer than dolphins! They slow their heart rate to just one-third of normal to conserve oxygen.", image: "🦥" },
  { id: 21, title: "Pink From Shrimp", emoji: "🦩", animal: "Flamingo", category: "Birds", fact: "Flamingos are born gray and turn pink from the shrimp and algae they eat! The carotenoid pigments in their food are what give them their signature color.", image: "🦩" },
  { id: 22, title: "Dads Give Birth", emoji: "🐎", animal: "Seahorse", category: "Ocean", fact: "Seahorses are the only animals where the male gives birth! The female deposits eggs into the male's pouch, where he fertilizes and carries them until they hatch.", image: "🐎" },
  { id: 23, title: "Egg-Laying Mammal", emoji: "🦫", animal: "Platypus", category: "Weird & Wonderful", fact: "The platypus is one of the few mammals that lays eggs! It also has a venomous spur on its hind legs and can detect electric fields with its bill.", image: "🦫" },
  { id: 24, title: "The Chillest Animal", emoji: "🦫", animal: "Capybara", category: "Mammals", fact: "Capybaras are so relaxed they often let other animals sit on them: birds, monkeys, even caimans! They're the largest rodents in the world and native to South America.", image: "🦫" },
  { id: 25, title: "Indestructible Water Bears", emoji: "🐻", animal: "Tardigrade", category: "Weird & Wonderful", fact: "Tardigrades (water bears) can survive in space, extreme temperatures from -328 degrees F to 300 degrees F, and even being completely dried out for decades!", image: "🐻" },
  { id: 26, title: "Unicorn of the Sea", emoji: "🐳", animal: "Narwhal", category: "Ocean", fact: "Narwhals have a long spiral tusk (up to 10 feet!) that is actually a tooth. Scientists believe they use it to sense water temperature and salinity.", image: "🐳" },
  { id: 27, title: "22-Hour Sleepers", emoji: "🐨", animal: "Koala", category: "Mammals", fact: "Koalas sleep up to 22 hours a day! Their diet of eucalyptus leaves is so low in nutrients and hard to digest that they need constant rest to conserve energy.", image: "🐨" },
  { id: 28, title: "Taste With Their Feet", emoji: "🦋", animal: "Butterfly", category: "Weird & Wonderful", fact: "Butterflies taste with their feet! They have taste receptors on their tarsi (feet) to check if a plant is suitable for laying eggs before they do.", image: "🦋" },
  { id: 29, title: "Arm Regeneration Masters", emoji: "⭐", animal: "Starfish", category: "Ocean", fact: "A single starfish arm can regenerate an entire new body! Some species can even split in half and grow into two complete starfish.", image: "⭐" },
  { id: 30, title: "Super-Fast Hearts", emoji: "🐦", animal: "Hummingbird", category: "Birds", fact: "A hummingbird's heart can beat up to 1,260 times per minute! Their wings also beat up to 80 times per second, allowing them to hover perfectly still.", image: "🐦" },
  { id: 31, title: "Spit Happens", emoji: "🦙", animal: "Alpaca", category: "Mammals", fact: "Alpacas spit when they're annoyed, threatened, or competing for food! It's their main defense mechanism and can travel up to 10 feet.", image: "🦙" },
  { id: 32, title: "Walking Pinecones", emoji: "🦔", animal: "Pangolin", category: "Weird & Wonderful", fact: "Pangolins are the only mammals covered in scales! When threatened, they roll into a tight ball, making them look like living pinecones.", image: "🦔" },
  { id: 33, title: "Underwater Makeover", emoji: "🐟", animal: "Blobfish", category: "Ocean", fact: "The blobfish only looks like a sad blob on land! In the deep ocean (where it lives), the pressure keeps it looking like a normal fish with a big nose.", image: "🐟" },
  { id: 34, title: "10kg Hearts", emoji: "🦒", animal: "Giraffe", category: "Mammals", fact: "A giraffe's heart weighs up to 25 pounds (11 kg) to pump blood all the way up its 6-foot neck! Their blood pressure is twice that of humans.", image: "🦒" },
  { id: 35, title: "Black Skin, Clear Fur", emoji: "🐻‍❄️", animal: "Polar Bear", category: "Mammals", fact: "Polar bears have black skin (to absorb heat) and transparent fur! Their fur only appears white because it reflects visible light, like snow.", image: "🐻‍❄️" },
  { id: 36, title: "Identical Quadruplets", emoji: "🛡️", animal: "Armadillo", category: "Mammals", fact: "Nine-banded armadillos always give birth to four identical babies from a single egg that splits: nature's own cloning!", image: "🛡️" },
  { id: 37, title: "Frozen But Alive", emoji: "🐸", animal: "Wood Frog", category: "Weird & Wonderful", fact: "Wood frogs can freeze solid during winter. Their heart stops, blood stops flowing, and up to 65% of their body water turns to ice! They thaw and hop away in spring.", image: "🐸" },
  { id: 38, title: "Balloon Defense", emoji: "🐡", animal: "Pufferfish", category: "Ocean", fact: "Pufferfish can inflate to three times their normal size when threatened! They also contain a toxin 1,200 times more deadly than cyanide.", image: "🐡" },
  { id: 39, title: "Months Without Eating", emoji: "🐍", animal: "Ball Python", category: "Reptiles", fact: "Ball pythons can go months without eating when they're in breeding season, and that's totally normal. It's a natural fasting behavior, not a sign of illness.", image: "🐍" },
  { id: 40, title: "The Wave of Peace", emoji: "🦎", animal: "Bearded Dragon", category: "Reptiles", fact: "Bearded dragons wave one arm as a submissive gesture to other dragons. It's their version of 'no threat here!' and a polite greeting in dragon language.", image: "🦎" },
  { id: 41, title: "Tail Fat Reserves", emoji: "🦎", animal: "Leopard Gecko", category: "Reptiles", fact: "Leopard geckos store fat reserves in their thick tails. A skinny tail can signal poor health or stress. A healthy gecko should have a plump, rounded tail.", image: "🦎" },
  { id: 42, title: "Rediscovered in 1994", emoji: "🦎", animal: "Crested Gecko", category: "Reptiles", fact: "Crested geckos were thought to be extinct until they were rediscovered in 1994 in New Caledonia! They're now one of the most popular gecko species in the hobby.", image: "🦎" },
  { id: 43, title: "Color Means Communication", emoji: "🦎", animal: "Chameleon", category: "Reptiles", fact: "Chameleons don't change color primarily for camouflage. They do it to communicate mood and temperature. Color changes signal stress, excitement, readiness to mate, and more.", image: "🦎" },
  { id: 44, title: "Three Eyelids", emoji: "🐶", animal: "Dog", category: "Dogs & Cats", fact: "Dogs have three eyelids. A third one called a nictitating membrane helps protect and moisten the eye. You can sometimes spot it when a dog is sleepy!", image: "🐶" },
  { id: 45, title: "Unique Nose Prints", emoji: "🐶", animal: "Dog", category: "Dogs & Cats", fact: "A dog's nose print is as unique as a human fingerprint. No two are alike! Some kennel clubs have started using nose prints for identification.", image: "🐶" },
  { id: 46, title: "Dogs Dream Too", emoji: "🐶", animal: "Dog", category: "Dogs & Cats", fact: "Dogs dream just like humans do. Their REM sleep looks remarkably similar to ours. You'll notice twitching paws and little whimpers as they relive their day.", image: "🐶" },
  { id: 47, title: "Born Blind and Deaf", emoji: "🐶", animal: "Dog", category: "Dogs & Cats", fact: "Puppies are born completely blind and deaf. They rely entirely on smell and touch for their first two weeks of life. Their eyes and ears open around 2 weeks old.", image: "🐶" },
  { id: 48, title: "Mental Fatigue is Real", emoji: "🐶", animal: "Dog", category: "Dogs & Cats", fact: "Regular mental stimulation is just as tiring for dogs as physical exercise. Puzzle feeders and training sessions work wonders for a calmer, happier pup.", image: "🐶" },
  { id: 49, title: "Meow is Just for Us", emoji: "🐱", animal: "Cat", category: "Dogs & Cats", fact: "Cats only meow at humans, not at other cats. They invented the meow specifically to communicate with people, and each cat develops its own unique vocabulary.", image: "🐱" },
  { id: 50, title: "Healing Purr", emoji: "🐱", animal: "Cat", category: "Dogs & Cats", fact: "A cat's purr vibrates at 25 to 150 Hz, a frequency known to promote bone healing and reduce stress, for both the cat and the human nearby!", image: "🐱" },
  { id: 51, title: "Always Landing Right", emoji: "🐱", animal: "Cat", category: "Dogs & Cats", fact: "Cats have a specialized collarbone that lets them always land on their feet. It's called the 'righting reflex' and kicks in within milliseconds of a fall.", image: "🐱" },
  { id: 52, title: "Lactose Intolerant Cats", emoji: "🐱", animal: "Cat", category: "Dogs & Cats", fact: "Adult cats are technically lactose intolerant, despite what cartoons suggest. Skip the milk bowl, it can cause upset stomachs and digestive issues.", image: "🐱" },
  { id: 53, title: "70% of Life Asleep", emoji: "🐱", animal: "Cat", category: "Dogs & Cats", fact: "Cats spend up to 70% of their lives sleeping. They are crepuscular, most active at dawn and dusk, and conserve energy the rest of the time.", image: "🐱" },
  { id: 54, title: "Parrots Need Company", emoji: "🦜", animal: "Parrot", category: "Birds", fact: "Parrots need social interaction daily. Isolation can cause feather plucking and behavioral issues. They're highly intelligent birds that thrive on engagement.", image: "🦜" },
  { id: 55, title: "Rabbits Need Exercise", emoji: "🐰", animal: "Rabbit", category: "Mammals", fact: "Rabbits are not low-maintenance pets. They need at least 3 hours of exercise outside their enclosure every day to stay healthy and mentally stimulated.", image: "🐰" },
  { id: 56, title: "Guinea Pigs Are Social", emoji: "🐹", animal: "Guinea Pig", category: "Mammals", fact: "Guinea pigs are highly social and should ideally be kept in pairs or small groups. A lone guinea pig can become lonely, anxious, and even depressed.", image: "🐹" },
  { id: 57, title: "100-Year Commitment", emoji: "🐢", animal: "Tortoise", category: "Reptiles", fact: "Tortoises can live for over 100 years, so adopting one is genuinely a lifelong commitment. You may need to include them in your will!", image: "🐢" },
  { id: 58, title: "Mimics Everything", emoji: "🦜", animal: "Parrot", category: "Birds", fact: "Many exotic birds can mimic not just words but full sentences, tones, and even laughs. Some African Greys have been recorded with vocabularies exceeding 1,000 words.", image: "🦜" },
  { id: 59, title: "Electric Sense", emoji: "🦈", animal: "Shark", category: "Ocean", fact: "Sharks have special jelly-filled pores called ampullae of Lorenzini that detect the tiny electrical fields produced by other animals' heartbeats. They can sense a heartbeat from over a meter away!", image: "🦈" },
  { id: 60, title: "Crow Tool Users", emoji: "🐦‍⬛", animal: "Crow", category: "Birds", fact: "New Caledonian crows craft hooked tools from twigs and leaves to extract grubs from bark, and they pass these techniques on to their young, making it a form of animal culture.", image: "🐦‍⬛" },
  { id: 61, title: "Hippo Sunscreen", emoji: "🦛", animal: "Hippo", category: "Mammals", fact: "Hippos secrete a reddish, oily fluid that acts as a natural sunscreen and antibiotic! Scientists once thought it was blood, earning it the nickname 'blood sweat.'", image: "🦛" },
  { id: 62, title: "Ants Farm Fungi", emoji: "🐜", animal: "Leafcutter Ant", category: "Weird & Wonderful", fact: "Leafcutter ants don't eat the leaves they carry. They use them to grow a special fungus inside their colony, which is their actual food source. They've been farming for over 50 million years!", image: "🐜" },
  { id: 63, title: "Mirror Test Passers", emoji: "🐬", animal: "Dolphin", category: "Ocean", fact: "Dolphins are one of only a handful of animals that pass the mirror self-recognition test, placing them alongside humans, great apes, and elephants as animals with a sense of self-awareness.", image: "🐬" },
  { id: 64, title: "Sky-High Sleepers", emoji: "🦅", animal: "Swift", category: "Birds", fact: "Common swifts can stay airborne for up to 10 months without landing. They eat, sleep, and even mate in the sky. They only land to breed!", image: "🦅" },
  { id: 65, title: "Finger-Snapping Shrimp", emoji: "🦐", animal: "Pistol Shrimp", category: "Ocean", fact: "Pistol shrimp snap their claws so fast it creates a cavitation bubble that reaches the temperature of the sun's surface (briefly!) and stuns or kills prey instantly.", image: "🦐" },
  { id: 66, title: "No Two Stripes Alike", emoji: "🦓", animal: "Zebra", category: "Mammals", fact: "Every zebra's stripe pattern is completely unique, like a fingerprint. Foals recognize their mothers by their stripe pattern alone within hours of being born.", image: "🦓" },
  { id: 67, title: "Wolves Change Rivers", emoji: "🐺", animal: "Wolf", category: "Mammals", fact: "When wolves were reintroduced to Yellowstone in 1995, they triggered a 'trophic cascade.' Their predation changed elk grazing patterns, which allowed vegetation to recover, stabilizing riverbanks and literally altering the course of rivers.", image: "🐺" },
  { id: 68, title: "Velvet Antlers Grow Fast", emoji: "🦌", animal: "Deer", category: "Mammals", fact: "Deer antlers are the fastest-growing tissue in the animal kingdom, growing up to an inch per day! They're covered in 'velvet,' a soft skin rich in blood vessels, until they harden each autumn.", image: "🦌" },
  { id: 69, title: "Born Male, Die Female", emoji: "🐟", animal: "Clownfish", category: "Ocean", fact: "All clownfish are born male. When the dominant female of a group dies, the largest male changes sex to become female permanently. Finding Nemo got it backwards!", image: "🐟" },
  { id: 70, title: "Snake Venom? No Thanks", emoji: "🦡", animal: "Honey Badger", category: "Mammals", fact: "Honey badgers are nearly immune to snake venom. They've been filmed getting bitten by cobras, going limp for a few minutes, then waking up and continuing to eat the snake.", image: "🦡" },
  { id: 71, title: "Nature's Sound Thief", emoji: "🐦", animal: "Lyrebird", category: "Birds", fact: "The lyrebird can perfectly mimic almost any sound it hears: chainsaws, car alarms, camera shutters, other bird species, and even human voices. They've been recorded mimicking entire construction sites.", image: "🐦" },
  { id: 72, title: "Hypnotic Skin", emoji: "🦑", animal: "Cuttlefish", category: "Ocean", fact: "Cuttlefish hypnotize prey by rippling hypnotic patterns across their skin at high speed. The dazzling light show freezes crabs and shrimp in place just long enough to strike.", image: "🦑" },
  { id: 73, title: "The Ultimate Impostor", emoji: "🐙", animal: "Mimic Octopus", category: "Ocean", fact: "The mimic octopus can impersonate over 15 different species, including lionfish, flatfish, and sea snakes, by reshaping its body and changing colour in real time to avoid predators.", image: "🐙" },
  { id: 74, title: "24 Eyes, Full Colour", emoji: "🪼", animal: "Box Jellyfish", category: "Ocean", fact: "Box jellyfish have 24 eyes arranged in four clusters, and unlike most jellyfish they can see in full colour. Despite having no brain, their eyes are structurally similar to human eyes.", image: "🪼" },
  { id: 75, title: "Regional Accents", emoji: "🐐", animal: "Goat", category: "Mammals", fact: "Goats develop regional accents. Kids raised in different social groups develop distinct bleats. Scientists say it's evidence of social learning in animals previously thought to have fixed vocalisations.", image: "🐐" },
  { id: 76, title: "Hear With Their Feet", emoji: "🐘", animal: "Elephant", category: "Mammals", fact: "Elephants communicate through seismic vibrations in the ground, detecting low-frequency rumbles with specialised receptors in their feet and trunk. They can 'hear' messages from other elephants up to 20 miles away.", image: "🐘" },
  { id: 77, title: "Boiling Chemical Spray", emoji: "🪲", animal: "Bombardier Beetle", category: "Weird & Wonderful", fact: "Bombardier beetles fire a boiling chemical spray from their abdomen at 100 degrees C with a rapid-fire popping sound, up to 500 pulses per second. The reaction between two stored chemicals creates an explosive defence.", image: "🪲" },
  { id: 78, title: "Magpie Self-Awareness", emoji: "🐦‍⬛", animal: "Magpie", category: "Birds", fact: "Magpies are the only non-mammal known to pass the mirror self-recognition test. When shown their reflection with a coloured dot on their feathers, they immediately try to investigate and remove it.", image: "🐦‍⬛" },
  // Dynamic facts (from DynamicFact database, baked in as static)
  { id: 79, title: "Secrets in the Sound", emoji: "🐬", animal: "Dolphin", category: "Ocean", fact: "Dolphins communicate using unique signature whistles that function like names! Each dolphin develops its own distinct whistle, allowing them to identify and call one another, much like how we use names to socialize.", image: "🐬" },
  { id: 80, title: "Glimmer in the Dark", emoji: "✨", animal: "Firefly", category: "Weird & Wonderful", fact: "Fireflies are not just beautiful; they're natural born chemists! These glowing insects produce light through a chemical reaction involving a substance called luciferin, which allows them to light up summer nights.", image: "✨" },
  { id: 81, title: "Color-Changing Camouflage", emoji: "🦎", animal: "Chameleon", category: "Reptiles", fact: "Chameleons are famous for their ability to change color, but did you know it's primarily a way to communicate? They alter their hues depending on their mood and social signals, rather than just blending into their surroundings!", image: "🦎" },
  { id: 82, title: "The Tiny Yet Mighty", emoji: "🐝", animal: "Honey Bee", category: "Weird & Wonderful", fact: "A single honey bee can visit up to 2,000 flowers in one day, making them key players in our ecosystem! Their tireless work as pollinators helps produce about one-third of the food we eat.", image: "🐝" },
  { id: 83, title: "Silent Signals", emoji: "🐙", animal: "Octopus", category: "Ocean", fact: "Octopuses have an extraordinary ability to communicate through color and texture! They can rapidly change their skin color and pattern to send signals to each other or confuse predators, making them masters of disguise.", image: "🐙" },
  { id: 84, title: "Dancing Crickets", emoji: "🐜", animal: "Cricket", category: "Weird & Wonderful", fact: "Crickets don't just chirp; they dance too! Male crickets perform elaborate moves while singing to attract females, showcasing their fitness and charm in a rhythmic ballet of nature.", image: "🐜" },
  { id: 85, title: "Multiple Personality Parrots", emoji: "🦜", animal: "African Grey Parrot", category: "Birds", fact: "African Grey Parrots are known for their exceptional intelligence and social skills, often mimicking human speech with astonishing accuracy. They can learn to use and even combine different phrases based on context, displaying personalities that can change depending on their environments!", image: "🦜" },
  { id: 86, title: "The Tardigrade Resilience", emoji: "🌌", animal: "Tardigrade", category: "Weird & Wonderful", fact: "Tardigrades, also known as water bears, can survive extreme conditions that would obliterate most life forms! They can endure boiling water, freezing temperatures, and even the vacuum of space - all while going into a state of cryptobiosis!", image: "🌌" },
  { id: 87, title: "Sharks Can Be Chatty", emoji: "🐋", animal: "Humpback Whale", category: "Ocean", fact: "Humpback Whales are not just majestic giants; they're also the singers of the sea! Males produce complex songs that can last for 20 minutes and can be heard over vast distances, possibly for mating purposes or simply to communicate with their fellow swimmers.", image: "🐋" },
  { id: 88, title: "Chameleon Color Change", emoji: "🦎", animal: "Chameleon", category: "Reptiles", fact: "Chameleons are famous for their color-changing abilities, but it's not just for camouflage! They change colors in response to mood, temperature, and even social signals, making them masters of both disguise and emotion!", image: "🦎" },
  { id: 89, title: "Frog Rainmakers", emoji: "🌧️", animal: "Cuban Tree Frog", category: "Weird & Wonderful", fact: "The Cuban Tree Frog has been dubbed the 'rainmaker' because its croaking sounds can stimulate rainfall. This unique ability is thought to help attract mates and can be heard from miles away, echoing in the tropical night!", image: "🌧️" },
  { id: 90, title: "Reptile Alarm Clock", emoji: "🐢", animal: "Green Sea Turtle", category: "Ocean", fact: "Green Sea Turtles can hold their breath for up to 5 hours while resting on the sea floor! They have exceptional adaptations that allow them to dive deep and stay submerged for long periods, making them one of the ocean's most efficient swimmers.", image: "🐢" },
  { id: 91, title: "The Snack Time Ant", emoji: "🍃", animal: "Leafcutter Ant", category: "Weird & Wonderful", fact: "Leafcutter Ants are not just workers; they are farmers! They cut leaves to cultivate a special fungus that they eat, creating a symbiotic relationship that showcases advanced farming techniques thousands of years before humans even thought of agriculture.", image: "🍃" },
  { id: 92, title: "Sloth Speedsters", emoji: "🦥", animal: "Three-Toed Sloth", category: "Mammals", fact: "Despite their slow reputation, Three-Toed Sloths are surprisingly good swimmers! They can hold their breath for up to 40 minutes while gliding through water, using their long arms to paddle with grace.", image: "🦥" },
  { id: 93, title: "Singing Spiders", emoji: "🕷️", animal: "Common House Spider", category: "Weird & Wonderful", fact: "Did you know that some Common House Spiders can 'sing'? They produce low-frequency vibrations to attract mates and communicate with each other, turning the quiet corners of your home into a surprising concert hall!", image: "🕷️" },
  { id: 94, title: "Surprising Sea Sponges", emoji: "🧽", animal: "Sea Sponge", category: "Ocean", fact: "Sea sponges may look like simple organisms, but they possess a remarkable ability to regenerate! If you cut a sponge in half, it can regrow itself completely, showcasing a form of resilience that not many animals can match.", image: "🧽" },
  { id: 95, title: "Octopus Ink Defense", emoji: "🐙", animal: "Octopus", category: "Weird & Wonderful", fact: "Did you know that octopuses have a unique defense mechanism in the form of ink? When threatened, they can release a cloud of ink that not only obscures their escape but can also temporarily impair a predator's sense of smell!", image: "🐙" },
  { id: 96, title: "The Purring Lemur", emoji: "🐒", animal: "Lemur", category: "Mammals", fact: "Lemurs purr just like cats, but they do it primarily to communicate with their family members! This soothing sound helps strengthen social bonds and keep everyone feeling safe in their close-knit groups.", image: "🐒" },
  { id: 97, title: "Birds Can Count", emoji: "🦜", animal: "African Grey Parrot", category: "Birds", fact: "African Grey Parrots are incredibly smart and can count! Studies have shown that these feathered mathematicians can understand numerical concepts, proving that they are not just pretty faces but also brainiacs of the avian world.", image: "🦜" },
  { id: 98, title: "Frog Freeze", emoji: "🐸", animal: "Wood Frog", category: "Reptiles", fact: "The Wood Frog has a remarkable survival strategy: it can survive being frozen solid during the winter months! Once temperatures warm up, this icy amphibian thaws out and hops away as if nothing ever happened!", image: "🐸" },
  { id: 99, title: "Fluffy Fish Friends", emoji: "🐠", animal: "Clownfish", category: "Ocean", fact: "Clownfish have a unique symbiotic relationship with sea anemones, providing each other with protection and food. The clownfish's mucus coating allows them to thrive among the anemone's stinging tentacles without harm!", image: "🐠" },
  { id: 100, title: "Butterfly Birthdays", emoji: "🦋", animal: "Mayfly", category: "Weird & Wonderful", fact: "Mayflies are known for their astonishingly short lifespans, sometimes living just a few hours as adults. These ephemeral insects spend years developing underwater before emerging, mating, and then dying in the same day!", image: "🦋" },
  { id: 101, title: "Bouncing Buddies", emoji: "🦘", animal: "Kangaroo", category: "Mammals", fact: "Kangaroos are born the size of a grape and crawl into their mother's pouch, where they continue developing. This incredible marsupial can hop at speeds of up to 40 mph, making it the fastest bouncer in the animal kingdom!", image: "🦘" },
  { id: 102, title: "Silent Swimmers", emoji: "🐙", animal: "Octopus", category: "Ocean", fact: "Octopuses have three hearts and blue blood, giving them a unique physiological edge in deep ocean environments. When they swim, one heart pumps blood to their body, while the other two focus on their gills!", image: "🐙" },
  { id: 103, title: "Swimmers in the Desert", emoji: "🐀", animal: "Kangaroo Rat", category: "Mammals", fact: "The kangaroo rat lives in the arid deserts of North America and can survive without ever drinking water! It gets all the moisture it needs from the seeds it eats, allowing it to thrive in extreme conditions where most animals would perish.", image: "🐀" },
  { id: 104, title: "Feline Mustache", emoji: "😺", animal: "Sphynx Cat", category: "Dogs & Cats", fact: "Sphynx cats are naturally hairless due to a genetic mutation, but their exposed skin is just as sensitive as ours! These quirky kitties are known for their affectionate nature and unique 'mustache' whiskers that contribute to their charming personality.", image: "😺" },
  { id: 105, title: "Glowing Oceans, No Joke!", emoji: "🐬", animal: "Dolphins", category: "Ocean", fact: "Dolphins are known to display behaviors that suggest they can produce bioluminescence! When they swim at night, the substances in their skin can reflect light from bioluminescent organisms, creating a spectacular glowing effect in the water.", image: "🐬" },
  { id: 106, title: "Mission Impossible Tails", emoji: "🐒", animal: "Tamarin Monkeys", category: "Mammals", fact: "Some tamarin monkeys possess an impressive ability for communication through tail movements! They can convey complex messages to their troop members, proving that these small primates have a social network as intricate as any involving humans.", image: "🐒" },
  { id: 107, title: "Egg Layers of Mystery", emoji: "🐢", animal: "Sea Turtles", category: "Reptiles", fact: "Did you know that female sea turtles can travel thousands of miles to return to the beach where they were born to lay their eggs? This incredible homing ability, combined with their long migrations, makes them one of the most fascinating ocean explorers!", image: "🐢" },
  { id: 108, title: "Armored Squirrels", emoji: "🦚", animal: "Pangolin", category: "Weird & Wonderful", fact: "Pangolins are the only mammals covered in scales, making them look like real-life armadillos! When threatened, they can curl up into a tight ball, using these scales as armor against predators.", image: "🦚" },
  { id: 109, title: "Underwater Fireworks", emoji: "🦑", animal: "Cuttlefish", category: "Ocean", fact: "Cuttlefish can change color and texture in the blink of an eye, using specialized skin cells called chromatophores. This makes them not only masters of camouflage but also mesmerizing underwater performers!", image: "🦑" },
  { id: 110, title: "Invisible Wings", emoji: "🦅", animal: "Red-footed Booby", category: "Birds", fact: "Red-footed boobies are known for their unusual fishing technique: they can dive from heights of up to 30 feet into the ocean to catch fish. What's even more fascinating? They can actually see clearly underwater thanks to their unique eye structure!", image: "🦅" },
  { id: 111, title: "Survival Specialists", emoji: "🐢", animal: "Box Turtle", category: "Reptiles", fact: "Box turtles can live for over 100 years, making them one of the longest-living pets out there. They can even survive for months without food, entering a hibernation-like state to preserve energy!", image: "🐢" },
  { id: 112, title: "Cuddle Drones", emoji: "🦔", animal: "Hedgehog", category: "Dogs & Cats", fact: "Hedgehogs can run at speeds up to 6 miles per hour, which is quite fast for such small creatures! But don't be fooled by their spiny exterior; they love to curl up into little balls for cuddles when they're feeling safe.", image: "🦔" },
  { id: 113, title: "Super Sneaky Narwhal", emoji: "🐋", animal: "Narwhal", category: "Ocean", fact: "Narwhals are often called the unicorns of the sea, thanks to their long, spiral tusks that can grow up to 10 feet long! Surprisingly, this tusk is actually an elongated tooth, and scientists believe it can detect changes in the environment, helping these mystical creatures navigate the frigid Arctic waters.", image: "🐋" },
  { id: 114, title: "Rollercoaster Tails", emoji: "🦜", animal: "Kookaburra", category: "Birds", fact: "Kookaburras have a laugh that's so distinctive it sounds like hearty human laughter! These birds use their famous calls to establish territory, and you'll often hear their chortles echoing through the Australian outback at sunrise.", image: "🦜" },
  { id: 115, title: "Electric Eel Shock", emoji: "⚡", animal: "Electric Eel", category: "Weird & Wonderful", fact: "Electric eels can produce jolts of electricity up to 600 volts, enough to stun a horse! They use this electric shock for hunting and self-defense, making them one of the most shocking animals in the Amazon river basin.", image: "⚡" },
  { id: 116, title: "Climbing the Walls", emoji: "🦎", animal: "Gecko", category: "Reptiles", fact: "Geckos have microscopic hairs on their feet that allow them to stick to surfaces and even run on ceilings! This amazing ability comes from van der Waals forces, making them one of nature's great climbers.", image: "🦎" },
  { id: 117, title: "Can't Stop Purring", emoji: "🐆", animal: "Cheetah", category: "Mammals", fact: "Unlike other big cats, cheetahs purr continuously, even while exhaling, creating a soothing sound! This unique vocalization signals contentment, making them the only large felines that never truly roar.", image: "🐆" },
  { id: 118, title: "Shrimp Anemone Alliance", emoji: "🐠", animal: "Clownfish", category: "Ocean", fact: "Clownfish and sea anemones share one of nature's most iconic partnerships. The clownfish gets shelter and protection from the anemone's stinging tentacles, while the anemone benefits from the clownfish cleaning parasites off its tentacles.", image: "🐠" },
  { id: 119, title: "Temperature-Switch Dragons", emoji: "🦎", animal: "Bearded Dragon", category: "Reptiles", fact: "Bearded dragons have a clever built-in trick: while genetics set their sex at conception, incubating eggs above 32°C (about 90°F) can turn genetic males into fully functional females. It's nature's smart way to balance populations in hot climates!", image: "🦎" },
  { id: 120, title: "Rhythm-Keeping Sea Lion", emoji: "🦭", animal: "California Sea Lion", category: "Ocean", fact: "Ronan the California sea lion is the first nonhuman mammal proven to keep a precise beat to music. She bobs her head in perfect sync and, according to recent studies, often matches or beats human consistency - even grooving to brand-new rhythms she's never heard before!", image: "🦭" },
  { id: 121, title: "Tube-Eyed Head Rotators", emoji: "🦉", animal: "Owl", category: "Birds", fact: "Owls don't have round eyeballs like us - they have fixed eye tubes locked tightly in their skull sockets. This gives them incredible night vision but zero eye movement, so they rotate their heads up to 270 degrees instead. Built-in swivel mode activated!", image: "🦉" },
  { id: 122, title: "Blue-Eyed Arctic Shifters", emoji: "🦌", animal: "Reindeer", category: "Mammals", fact: "Reindeer are the only mammals known to change their eye color with the seasons! Their eyes shift from golden in summer to a brilliant blue in winter, boosting their ability to see in the dim Arctic twilight. Nature's own seasonal night-vision upgrade!", image: "🦌" },
  { id: 123, title: "Miracle Mike the Headless Rooster", emoji: "🐔", animal: "Chicken", category: "Birds", fact: "In 1945, a rooster named Miracle Mike lived for over 18 months after his head was chopped off! The axe missed his brain stem, and he became a famous traveling sideshow attraction. Talk about legendary resilience!", image: "🐔" },
  { id: 124, title: "Gliding Rainforest Acrobat", emoji: "🐸", animal: "Wallace's Flying Frog", category: "Weird & Wonderful", fact: "Wallace's flying frog doesn't just leap - it glides like a tiny amphibian paraglider! Using its enormous webbed feet as parachutes and rudders, it can steer mid-air, control its descent, and safely land on distant rainforest branches.", image: "🐸" },
  { id: 125, title: "Instant Slime Escape Artist", emoji: "🐟", animal: "Hagfish", category: "Weird & Wonderful", fact: "The hagfish is the undisputed slime champion. When threatened, it can release up to a liter of thick, sticky goo in just 0.1 seconds - enough to expand in water and completely clog a predator's gills for a perfect smoky getaway!", image: "🐟" },
  { id: 126, title: "Hairy Oxygen-Boosting Dads", emoji: "🐸", animal: "Hairy Frog", category: "Weird & Wonderful", fact: "During breeding season, male hairy frogs grow temporary 'hair' - actually frilly fringes of skin packed with blood vessels - along their sides and legs. These help the devoted dads absorb extra oxygen while guarding eggs in fast-flowing, low-oxygen streams.", image: "🐸" },
  { id: 127, title: "Boozy Nectar-Loving Shrew", emoji: "🐿️", animal: "Pen-tailed Tree Shrew", category: "Mammals", fact: "The pen-tailed tree shrew starts every day with a built-in happy hour! It feasts on fermented palm nectar that's naturally about 3.8% alcohol (roughly beer strength). Special metabolic enzymes keep it perfectly sober and ready for more - nature's ultimate functional drinker!", image: "🐿️" },
  { id: 128, title: "Pebble-Proposing Love Birds", emoji: "🐧", animal: "Gentoo and Adélie Penguin", category: "Birds", fact: "Male gentoo and Adélie penguins are true romantics. They carefully select the perfect smooth pebble and present it to their chosen female. If she accepts, they use it to build their nest - and often start a lifelong pair bond. A well-chosen pebble says 'I love you' in penguin!", image: "🐧" },
  { id: 129, title: "Locked-In Gliders", emoji: "🕊️", animal: "Wandering Albatross", category: "Birds", fact: "Wandering albatrosses have a special tendon that locks their wings open, letting them glide for hours over open ocean without flapping once. With wingspans up to 11 feet, they're the largest of any living bird and can circle the globe on wind alone.", image: "🕊️" },
  { id: 130, title: "Built-In Crash Helmets", emoji: "🐦", animal: "Woodpecker", category: "Birds", fact: "Woodpeckers peck up to 20 times per second without getting concussions, thanks to spongy skull bone and a long tongue that wraps around the skull like an internal seatbelt, cushioning the brain with every strike.", image: "🐦" },
  { id: 131, title: "The Nonstop Flyer", emoji: "🐦", animal: "Bar-Tailed Godwit", category: "Birds", fact: "A bar-tailed godwit was once tracked flying over 13,000 km from Alaska to Australia without a single stop to eat, drink, or rest, the longest nonstop flight ever recorded for any bird.", image: "🐦" },
  { id: 132, title: "Fastest Animal Alive", emoji: "🦅", animal: "Peregrine Falcon", category: "Birds", fact: "Peregrine falcons are the fastest animals on Earth, reaching speeds over 240 mph when diving after prey. Tiny bony baffles in their nostrils let them breathe safely at those speeds without damaging their lungs.", image: "🦅" },
  { id: 133, title: "Cancer-Proof and Cold-Blooded", emoji: "🐀", animal: "Naked Mole Rat", category: "Weird & Wonderful", fact: "Naked mole rats are nearly immune to cancer and can survive up to 18 minutes without oxygen by switching their metabolism to run on fructose, like a plant. They're also one of the only mammals that can't regulate their own body temperature.", image: "🐀" },
  { id: 134, title: "The Ultimate Clingy Partner", emoji: "🐟", animal: "Anglerfish", category: "Ocean", fact: "Male anglerfish are a fraction of the female's size, and in some species he fuses permanently to her body, their skin and blood vessels merging until he becomes little more than a built-in supply of sperm for life.", image: "🐟" },
  { id: 135, title: "Self-Eviction Defense", emoji: "🥒", animal: "Sea Cucumber", category: "Ocean", fact: "When threatened, some sea cucumbers can expel their own internal organs through their rear end to confuse predators, then simply regrow a full set of organs within weeks.", image: "🥒" },
  { id: 136, title: "Nature's Biggest Gamble", emoji: "🐟", animal: "Ocean Sunfish", category: "Ocean", fact: "Ocean sunfish (mola mola) lay more eggs than any other vertebrate on Earth, up to 300 million at once, banking on sheer numbers since almost none survive to adulthood.", image: "🐟" },
  { id: 137, title: "Dinner-Plate Eyes", emoji: "🦑", animal: "Giant Squid", category: "Ocean", fact: "Giant squid have the largest eyes in the animal kingdom, up to 27 cm across, roughly the size of a dinner plate, built to catch the faintest flickers of bioluminescent light in the deep sea.", image: "🦑" },
  { id: 138, title: "Faster Than a Fighter Pilot", emoji: "🦎", animal: "Chameleon", category: "Reptiles", fact: "A chameleon's tongue accelerates fast enough to briefly pull more G-force than a human fighter pilot can withstand. It can strike a full body-length away and snap back with its prey in a fraction of a second.", image: "🦎" },
  { id: 139, title: "The Reptile With a Third Eye", emoji: "🦎", animal: "Tuatara", category: "Reptiles", fact: "Tuataras have a light-sensing 'third eye' on top of their skull, a metabolism so slow they can live past 100, and a lineage that predates the dinosaurs. They're the last survivor of an entire reptile order.", image: "🦎" },
  { id: 140, title: "All Bite, No Bark", emoji: "🐊", animal: "American Alligator", category: "Reptiles", fact: "An alligator's jaw can clamp down with nearly 3,000 pounds of bite force, one of the strongest bites of any living animal. Ironically, the muscles that open its jaw are so weak a person can hold its mouth shut with bare hands.", image: "🐊" },
  { id: 141, title: "The Flying Dragon", emoji: "🦎", animal: "Draco Lizard", category: "Reptiles", fact: "Draco lizards have rib bones that extend into wing-like flaps of skin, letting them glide as far as 60 meters between trees without ever flapping a single limb.", image: "🦎" },
  { id: 142, title: "Fastest Eater Alive", emoji: "🐾", animal: "Star-Nosed Mole", category: "Weird & Wonderful", fact: "The star-nosed mole's nose has 22 fleshy tentacles packed with over 25,000 sensory receptors. It can identify and eat food in about 120 milliseconds, the fastest eating speed recorded in any mammal.", image: "🐾" },
  { id: 143, title: "Built-In Sonar", emoji: "🦇", animal: "Bat", category: "Mammals", fact: "Bats are the only mammals capable of true, sustained flight. Many species navigate in total darkness using echolocation, firing off up to 200 calls per second and reading the echoes to build a live map of their surroundings.", image: "🦇" },
  { id: 144, title: "Two-Hour Breath Holders", emoji: "🦭", animal: "Elephant Seal", category: "Mammals", fact: "Elephant seals can dive over 2,000 meters deep and hold their breath for up to two hours, longer than almost any other mammal, by collapsing their lungs and slowing their heart to just a few beats per minute.", image: "🦭" },
  { id: 145, title: "Can't Taste Sugar", emoji: "🐱", animal: "Cat", category: "Dogs & Cats", fact: "Cats are one of the only mammals that physically cannot taste sweetness. A mutation disabled their sugar taste receptor long ago, so that slice of cake means nothing to your cat, no matter how much they beg.", image: "🐱" },
  { id: 146, title: "The Dog That Doesn't Bark", emoji: "🐶", animal: "Basenji", category: "Dogs & Cats", fact: "Basenjis have an unusually shaped larynx that keeps them from barking like other dogs. Instead they make a yodel-like sound nicknamed the 'baroo,' earning them the nickname 'the barkless dog.'", image: "🐶" },
  { id: 147, title: "A Nose Built Different", emoji: "🐶", animal: "Dog", category: "Dogs & Cats", fact: "A dog's sense of smell is estimated to be 10,000 to 100,000 times more sensitive than a human's. Their wet nose actually helps by trapping scent chemicals so they can be analyzed more effectively.", image: "🐶" },
  { id: 148, title: "Built-In Measuring Tape", emoji: "🐱", animal: "Cat", category: "Dogs & Cats", fact: "A cat's whiskers are roughly as wide as its body, and it uses them to judge whether a gap is safe to squeeze through before ever attempting it.", image: "🐱" },
  { id: 149, title: "Not a Suffocation Squeeze", emoji: "🐍", animal: "Boa Constrictor", category: "Reptiles", fact: "Boa constrictors don't kill by suffocating their prey. A study by biologist Scott Boback and colleagues found that constriction cuts off blood flow so fast that a prey animal's blood pressure crashes and it faints within seconds, well before it would ever suffocate. They also still carry tiny vestigial hind-leg spurs, leftover bones from ancestors that once walked on legs!", image: "🐍" },
  { id: 150, title: "The Vitamin C Shortage", emoji: "🐹", animal: "Guinea Pig", category: "Mammals", fact: "Guinea pigs 'popcorn,' leaping straight up and twisting mid-air, when they're overjoyed. Like humans, they can't produce their own Vitamin C, so their diet needs a daily dose of fresh veggies or they risk getting scurvy!", image: "🐹" },
  { id: 151, title: "The One-Leg Trick", emoji: "🦩", animal: "Flamingo", category: "Birds", fact: "Flamingos often stand balanced on a single leg for hours, a habit researchers believe helps them conserve body heat while wading in cold water. They can even sleep this way, locking a joint in place so it takes no extra muscle effort to stay balanced.", image: "🦩" },
  { id: 152, title: "No Stomach, No Problem", emoji: "🐎", animal: "Seahorse", category: "Ocean", fact: "Seahorses have no stomach at all, so food passes through them so quickly that they must graze almost constantly, some species eating thousands of tiny shrimp a day just to survive. They're also famously bad swimmers, fluttering a tiny dorsal fin up to 35 times a second just to inch forward.", image: "🐎" },
  { id: 153, title: "Wings Built for Silence", emoji: "🦉", animal: "Owl", category: "Birds", fact: "An owl's flight is almost completely silent thanks to comb-like serrations on the leading edge of its feathers, which break up turbulence, plus a soft, velvety surface that muffles any remaining sound. This lets them swoop down on prey that never hears them coming.", image: "🦉" },
  { id: 154, title: "Never Forgets a Flockmate", emoji: "🐔", animal: "Chicken", category: "Birds", fact: "Chickens are far smarter than they get credit for. Hens can recognize and remember dozens of individual flock members, and familiar humans, by sight over long stretches of time, and newborn chicks show early signs of 'object permanence' (understanding something still exists once it's hidden from view) within just days of hatching.", image: "🐔" },
  { id: 155, title: "Stripes That Repel Flies", emoji: "🦓", animal: "Zebra", category: "Mammals", fact: "A well-supported theory holds that zebra stripes make it hard for biting flies like horseflies to land safely. Filmed side by side, flies approached zebras and nearby horses at similar rates, but actually touched down on the zebras less than a quarter as often, likely because the sharp black-and-white contrast confuses a fly's ability to slow down and control its landing.", image: "🦓" },
  { id: 156, title: "Same Neck Bones as You", emoji: "🦒", animal: "Giraffe", category: "Mammals", fact: "A giraffe's towering neck contains exactly seven vertebrae, the same number found in a human neck, just enormously stretched out. In the wild they also get by on remarkably little sleep, one tracking study recording as little as 10 minutes a night, taken in a couple of short bursts; giraffes in zoos, with no predators to worry about, sleep several hours more.", image: "🦒" },
  { id: 157, title: "Fingerprints Like Ours", emoji: "🐨", animal: "Koala", category: "Mammals", fact: "Koalas are one of the only animals besides primates to have fingerprints, and theirs are so close to human fingerprints that even under a microscope, forensic experts have had trouble telling them apart.", image: "🐨" },
  { id: 158, title: "Zero to Sixty in Seconds", emoji: "🐆", animal: "Cheetah", category: "Mammals", fact: "Cheetahs can accelerate from 0 to 60 mph in about three seconds, faster than most sports cars, but they can only hold top speed for around 20-30 seconds before overheating. Unlike other big cats, their claws don't fully retract, working like cleats to grip the ground mid-sprint.", image: "🐆" },
  { id: 159, title: "The Loose-Skin Escape Artist", emoji: "🦡", animal: "Honey Badger", category: "Mammals", fact: "A honey badger's skin is so thick and loose that it can twist almost freely inside it, letting the animal spin around and bite an attacker even while pinned by the scruff of its neck. That fearlessness earned it a Guinness World Records title for most fearless animal on the planet.", image: "🦡" },
  { id: 160, title: "Always Running Warm", emoji: "😺", animal: "Sphynx Cat", category: "Dogs & Cats", fact: "With no fur coat for insulation, Sphynx cats run a noticeably higher body temperature and faster metabolism than other cats, which is why they seek out warm laps and sunny windowsills and often need sweaters in winter. They also need regular baths since their skin oils have nowhere else to go.", image: "😺" },
  { id: 161, title: "Married for Twenty Years", emoji: "🦐", animal: "Mantis Shrimp", category: "Ocean", fact: "Despite their fearsome punch, some mantis shrimp species are surprisingly devoted partners. Pairs like Lysiosquillina maculata mate for life, sharing the same burrow together for up to 20 years.", image: "🦐" },
  { id: 162, title: "A Million Hairs Per Inch", emoji: "🦦", animal: "Sea Otter", category: "Ocean", fact: "Sea otters have the densest fur of any animal on Earth, up to a million hairs packed into a single square inch. With no blubber to keep them warm, that fur trapping air bubbles is their only insulation, so they spend hours every day grooming to keep it in top shape.", image: "🦦" },
  { id: 163, title: "Stomach on the Outside", emoji: "⭐", animal: "Starfish", category: "Ocean", fact: "Starfish have no brain and no blood, moving instead through a water-powered hydraulic system that pumps seawater through hundreds of tiny tube feet. When eating something too big to swallow, they simply push their own stomach out through their mouth and digest it externally.", image: "⭐" },
  { id: 164, title: "A Bite That Won't Clot", emoji: "🦎", animal: "Komodo Dragon", category: "Reptiles", fact: "For decades scientists believed toxic mouth bacteria killed a Komodo dragon's prey, but research later revealed real venom glands that stop blood from clotting and crash the victim's blood pressure. When they do get a meal, they can eat up to 80% of their own body weight in one sitting.", image: "🦎" },
  { id: 165, title: "Sealed Shut Like a Box", emoji: "🐢", animal: "Box Turtle", category: "Reptiles", fact: "A box turtle's bottom shell has a hinge that lets it close up almost completely, sealing itself inside like, well, a box. They also have a powerful memory of home: if moved far from their territory, they'll often spend years trying to find their way back, which is why wildlife experts say never to relocate one you find.", image: "🐢" },
  { id: 166, title: "The Radiation Shield Protein", emoji: "🧬", animal: "Tardigrade", category: "Weird & Wonderful", fact: "Tardigrades produce a protein nicknamed Dsup ('damage suppressor') that coats their DNA and shields it from radiation damage. In a 2016 study, scientists inserted the Dsup gene into cultured human cells and found it cut radiation-induced DNA damage by about 40%, boosting the cells' radiation resistance.", image: "🧬" },
  { id: 167, title: "A Tongue Longer Than Its Body", emoji: "👅", animal: "Pangolin", category: "Weird & Wonderful", fact: "Pangolins have no teeth at all. Instead they rely on a sticky tongue that can stretch longer than their own head and body combined, anchored all the way back near their pelvis, to slurp up ants and termites by the thousands.", image: "👅" },
  { id: 168, title: "Forever Young, Forever Underwater", emoji: "🦎", animal: "Axolotl", category: "Weird & Wonderful", fact: "Axolotls never grow up in the usual salamander sense. Thanks to a trait called neoteny, they keep their feathery gills and stay fully aquatic for their entire lives, reaching adulthood without ever setting foot on land. Sadly, the wild population now survives in just one place, a shrinking canal system near Mexico City.", image: "🦎" },
  { id: 169, title: "The Alpha Wolf Myth", emoji: "🐺", animal: "Wolf", category: "Mammals", fact: "The famous 'alpha wolf' idea came from 1970s studies of unrelated wolves thrown together in captivity, which triggered artificial power struggles. Decades later, the same biologist who coined the term studied wild wolf packs and found they're simply family units, a breeding pair and their pups, not a rank ladder fought over. He spent years afterward trying to get the myth retracted.", image: "🐺" },
  { id: 170, title: "Milk Without Nipples", emoji: "🦫", animal: "Platypus", category: "Weird & Wonderful", fact: "Platypuses don't have nipples. Instead, mothers sweat milk through specialized patches of skin on their belly, and it pools into little grooves for the babies to lap up. It's one of several oddities that come from being a mammal that also lays eggs.", image: "🦫" },
  { id: 171, title: "Flying Backwards, Sleeping Like the Dead", emoji: "🐦", animal: "Hummingbird", category: "Birds", fact: "Hummingbirds are the only birds that can fly backwards, and even hover upside down for a moment, thanks to a unique shoulder joint that lets their wings rotate in a full circle. At night they drop into torpor, slashing their heart rate by up to 95%, since their tiny bodies burn through energy too fast to survive till morning otherwise.", image: "🐦" },
  { id: 172, title: "A Thumb That Isn't a Thumb", emoji: "🐼", animal: "Red Panda", category: "Mammals", fact: "Red pandas grip bamboo with a 'false thumb,' an extended wrist bone that works like an extra digit. Giant pandas independently evolved the exact same trick despite not being closely related to red pandas at all, a textbook case of two unrelated species landing on the same solution.", image: "🐼" },
  { id: 173, title: "Built-In Snorkel Mode", emoji: "🦫", animal: "Capybara", category: "Mammals", fact: "Capybaras can hold their breath underwater for up to 5 minutes to hide from jaguars and caimans. Their eyes, ears, and nostrils sit high on their head, like a hippo's, so they can stay almost fully submerged and still see, hear, and breathe.", image: "🦫" },
  { id: 174, title: "2,000 Teeth and Counting", emoji: "🐊", animal: "Alligator", category: "Reptiles", fact: "Alligators go through 2,000 to 3,000 teeth over a lifetime. Each of their roughly 80 teeth has a replacement already growing underneath, ready to push the old one out the moment it wears down or snaps off.", image: "🐊" },
  { id: 175, title: "Stomach Acid That Kills Anthrax", emoji: "🦅", animal: "Vulture", category: "Birds", fact: "A vulture's stomach acid is so corrosive, with a pH near zero, that it can destroy anthrax, botulism, and cholera bacteria before they ever reach the bloodstream. It's basically a built-in hazmat suit for eating roadkill.", image: "🦅" },
  { id: 176, title: "Bloody Generous", emoji: "🦇", animal: "Vampire Bat", category: "Mammals", fact: "Vampire bats that feed well will regurgitate blood to share with hungry roost-mates, but usually only ones who have groomed and shared with them before. Skip your turn to share, and the colony remembers.", image: "🦇" },
  { id: 177, title: "Steered By the Milky Way", emoji: "🪲", animal: "Dung Beetle", category: "Weird & Wonderful", fact: "Dung beetles are the only known insect that navigates by the Milky Way. On moonless nights, they take a mental snapshot of the galaxy's bright band overhead to roll their dung ball in a straight line, away from rivals.", image: "🪲" },
  { id: 178, title: "The Loudest Animal Alive", emoji: "🐋", animal: "Sperm Whale", category: "Ocean", fact: "Sperm whale echolocation clicks can reach 230 decibels underwater, the loudest sound any animal produces, powerful enough to be felt in a diver's chest from meters away. They use it to hunt giant squid in total darkness thousands of feet down.", image: "🐋" },
];

